import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, ShoppingCart, Store, Radar, BellRing } from 'lucide-react';
import { api } from '../services/api'; 
import { useCart } from '../context/CartContext'; 
import { calcularDistancia } from '../utils/radarService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const PanelCliente = () => {
  const [tab, setTab] = useState('tienda'); 
  const [ofertasPorLocal, setOfertasPorLocal] = useState({});
  const { cart, addToCart, count, clearCart } = useCart(); 
  const [pedidos, setPedidos] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [verCarrito, setVerCarrito] = useState(false);
  const [miUbicacion, setMiUbicacion] = useState(null);
  const [radarActivo, setRadarActivo] = useState(false);
  const [notificaciones, setNotificaciones] = useState([]);
  const [favoritos, setFavoritos] = useState([]); 
  const [loading, setLoading] = useState(true);

  const searchTimer = useRef(null);
  const userSession = JSON.parse(localStorage.getItem('user-session') || "{}");
  const currentUserId = userSession.user?.id;

  // --- APRENDIZAJE DE INTERESES (Persistencia Local) ---
  const registrarInteres = useCallback((terminos) => {
    if (!currentUserId) return;
    const palabras = Array.isArray(terminos) ? terminos : [terminos];
    setFavoritos(prev => {
      let nuevosFavs = [...prev];
      palabras.forEach(p => {
        if (typeof p !== 'string') return;
        const limpia = p.toLowerCase().split(' ')[0].replace(/[^a-z]/g, '');
        if (limpia.length > 2 && !nuevosFavs.includes(limpia)) {
          nuevosFavs.push(limpia);
        }
      });
      const sliceFinal = nuevosFavs.slice(-15);
      localStorage.setItem(`favs-${currentUserId}`, JSON.stringify(sliceFinal));
      return sliceFinal;
    });
  }, [currentUserId]);

  // --- CARGA DE DATOS DESDE LA API (MONGODB) ---
  const cargarDatosDesdeDB = async () => {
    setLoading(true);
    try {
      // 1. Obtener todas las ofertas
      const todasLasOfertas = await api.getTodasLasOfertas();
      
      // 2. Agrupar por local
      const agrupado = todasLasOfertas.reduce((acc, oferta) => {
        const local = oferta.local;
        if (!local) return acc;
        if (!acc[local.nombre]) {
          acc[local.nombre] = { 
            info: { 
                id: local._id, 
                nombre: local.nombre, 
                direccion: local.direccion,
                lng: local.location?.coordinates[0],
                lat: local.location?.coordinates[1]
            }, 
            ofertas: [] 
          };
        }
        acc[local.nombre].ofertas.push(oferta);
        return acc;
      }, {});
      
      setOfertasPorLocal(agrupado);

      // 3. Cargar Pedidos Reales de la DB
      const resPedidos = await fetch(`http://localhost:5000/api/pedidos/cliente/${currentUserId}`);
      if(resPedidos.ok) {
          const dataPedidos = await resPedidos.json();
          setPedidos(dataPedidos);
      }
    } catch (error) {
      console.error("Error cargando datos:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (currentUserId) {
      cargarDatosDesdeDB();
      const guardados = JSON.parse(localStorage.getItem(`favs-${currentUserId}`) || "[]");
      setFavoritos(guardados);
    }
  }, [currentUserId]);

  // --- LÓGICA DE RADAR ---
  useEffect(() => {
    let watchId = null;
    if (radarActivo && navigator.geolocation) {
      watchId = navigator.geolocation.watchPosition((pos) => {
        const { latitude, longitude } = pos.coords;
        setMiUbicacion({ lat: latitude, lng: longitude });
        
        const encontradas = [];
        Object.values(ofertasPorLocal).forEach(grupo => {
          grupo.ofertas.forEach(o => {
            const coincide = favoritos.some(fav => o.producto.toLowerCase().includes(fav));
            if (coincide && grupo.info.lat && grupo.info.lng) {
              const d = calcularDistancia(latitude, longitude, grupo.info.lat, grupo.info.lng);
              if (d <= 0.8) { 
                  encontradas.push({ ...o, dist: d.toFixed(2), localNombre: grupo.info.nombre });
              }
            }
          });
        });
        setNotificaciones(encontradas);
      }, (err) => console.error(err), { enableHighAccuracy: true });
    }
    return () => { if (watchId) navigator.geolocation.clearWatch(watchId); };
  }, [radarActivo, ofertasPorLocal, favoritos]);

  const handlePago = async (total) => {
    const pedidoData = {
      cliente: currentUserId,
      items: cart.map(item => ({
        producto: item.producto,
        precio: item.precio,
        cantidad: 1,
        localId: item.local._id || item.local
      })),
      total,
      puntoEntrega: miUbicacion
    };

    try {
        const res = await fetch('http://localhost:5000/api/pedidos', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(pedidoData)
        });
        if(res.ok) {
            alert("¡Pedido enviado con éxito!");
            clearCart();
            await cargarDatosDesdeDB(); 
            setVerCarrito(false);
            setTab('proceso');
        }
    } catch (e) {
        alert("Error al conectar con el servidor");
    }
  };

  if (loading) return <div style={loaderStyle}>Conectando con la base de datos...</div>;

  return (
    <div style={layout}>
      <aside style={sidebar}>
        <div style={logoEspacio}>
          <h2 style={{color: '#e67e22', margin: 0}}>OfertasAPP</h2>
          <small style={{color: '#a0aec0'}}>Hola, {userSession.user?.nombre || 'Usuario'}</small>
        </div>
        <nav style={navItems}>
          <button onClick={() => {setTab('tienda'); setVerCarrito(false)}} style={tab === 'tienda' && !verCarrito ? btnActive : btn}><ShoppingBag size={20}/> Tienda</button>
          <button onClick={() => {setVerCarrito(true); setTab('tienda')}} style={verCarrito ? btnActive : btn}><ShoppingCart size={20}/> Carrito ({count})</button>
          <button onClick={() => {setTab('proceso'); setVerCarrito(false)}} style={tab === 'proceso' ? btnActive : btn}><Clock size={20}/> En Proceso</button>
          <button onClick={() => {setTab('historial'); setVerCarrito(false)}} style={tab === 'historial' ? btnActive : btn}><CheckCircle size={20}/> Historial</button>
        </nav>
      </aside>

      <main style={main}>
        {tab === 'tienda' && !verCarrito && (
          <>
            <div style={radarCard(radarActivo)}>
              <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
                <div style={radarCircle(radarActivo)}><Radar size={24} color={radarActivo ? "#fff" : "#e67e22"} /></div>
                <div style={{flex: 1}}>
                  <h3 style={{margin: 0, fontSize: '1rem'}}>Radar de Ahorro Inteligente</h3>
                  <p style={{margin: 0, fontSize: '0.8rem', opacity: 0.8}}>
                    {radarActivo ? `Vigilando ofertas de: ${favoritos.join(', ')}` : 'Activa el radar para detectar ofertas cerca tuyo.'}
                  </p>
                </div>
                <button onClick={() => setRadarActivo(!radarActivo)} style={btnRadar(radarActivo)}>
                  {radarActivo ? 'DESACTIVAR' : 'ACTIVAR'}
                </button>
              </div>
              
              {radarActivo && notificaciones.length > 0 && (
                <div style={notifBox}>
                  {notificaciones.map(n => (
                    <div key={n._id} style={notifItem}>
                      <BellRing size={18} color="#e67e22" />
                      <div style={{flex: 1}}>
                        <div style={{fontSize: '0.85rem', fontWeight: 'bold'}}>¡{n.producto} encontrado!</div>
                        <div style={{fontSize: '0.75rem'}}>{n.localNombre} • A {n.dist} km de ti</div>
                      </div>
                      <button style={btnIr} onClick={() => addToCart(n)}>+$ {n.precio}</button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div style={searchBox}>
              <MapPin size={20} color="#e67e22" />
              <input 
                style={input} 
                placeholder="Busca comida, bebidas o productos..." 
                value={busqueda} 
                onChange={(e) => {
                    setBusqueda(e.target.value);
                    if (searchTimer.current) clearTimeout(searchTimer.current);
                    searchTimer.current = setTimeout(() => registrarInteres(e.target.value), 1500);
                }} 
              />
            </div>

            {Object.keys(ofertasPorLocal).map(nombreLocal => {
              const local = ofertasPorLocal[nombreLocal].info;
              const dist = miUbicacion && local.lat ? calcularDistancia(miUbicacion.lat, miUbicacion.lng, local.lat, local.lng).toFixed(1) : "--";
              
              return (
                <div key={nombreLocal} style={tiendaSeccion}>
                  <div style={headerTienda}>
                    <div style={avatarTienda}><Store size={24} color="#e67e22" /></div>
                    <div>
                      <h3 style={{margin: 0}}>{nombreLocal}</h3>
                      <div style={metaTienda}>
                        <span>📍 {local.direccion}</span>
                        <span style={{color: '#27ae60', fontWeight: 'bold'}}> • {dist} km</span>
                      </div>
                    </div>
                  </div>
                  <div style={scrollRow}>
                    {ofertasPorLocal[nombreLocal].ofertas
                      .filter(o => o.producto.toLowerCase().includes(busqueda.toLowerCase()))
                      .map(o => (
                        <div key={o._id} style={cardShop}>
                          <img src={o.imagenUrl || "/api/placeholder/400/320"} style={imgShop} alt={o.producto} />
                          <div style={{padding: '12px'}}>
                            <h4 style={{margin: '0', fontSize: '0.9rem'}}>{o.producto}</h4>
                            <div style={pPrecio}>${o.precio}</div>
                            <button style={btnAdd} onClick={() => addToCart(o)}>
                                <ShoppingCart size={14} /> Agregar
                            </button>
                          </div>
                        </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </>
        )}

        {verCarrito && (
          <div style={cartContainerStyle}>
            <Carrito onCheckout={handlePago} />
          </div>
        )}

        {tab === 'proceso' && (
          <div style={centerCont}>
            <h2 style={{display:'flex', alignItems:'center', gap:'10px'}}><Clock color="#e67e22"/> Pedidos en camino</h2>
            {pedidos.filter(p => p.estado === 'proceso').length === 0 ? (
                <p style={{color:'#64748b'}}>No tienes pedidos activos actualmente.</p>
            ) : (
                pedidos.filter(p => p.estado === 'proceso').map(p => (
                    <SeguimientoPedido key={p._id} pedido={p} />
                ))
            )}
          </div>
        )}

        {tab === 'historial' && (
          <div style={centerCont}>
             <h2 style={{display:'flex', alignItems:'center', gap:'10px'}}><CheckCircle color="#27ae60"/> Historial de compras</h2>
             {pedidos.filter(p => p.estado === 'completado').map(p => (
               <div key={p._id} style={historialCard}>
                 <div>
                   <div style={{fontWeight: 'bold'}}>Compra en {p.local?.nombre}</div>
                   <small style={{color:'#94a3b8'}}>{new Date(p.createdAt).toLocaleDateString()}</small>
                 </div>
                 <div style={{textAlign: 'right'}}>
                   <div style={{color: '#e67e22', fontWeight:'bold'}}>${p.total}</div>
                   <small style={{color:'#27ae60'}}>Finalizado</small>
                 </div>
               </div>
             ))}
          </div>
        )}
      </main>
    </div>
  );
};

// --- ESTILOS COMPLETOS ---
const layout = { display: 'flex', height: '100vh', background: '#f8fafc', overflow: 'hidden', fontFamily: 'system-ui' };
const sidebar = { width: '260px', background: '#1a202c', color: 'white', display: 'flex', flexDirection: 'column', padding: '20px' };
const logoEspacio = { padding: '20px 0 40px 10px' };
const navItems = { display: 'flex', flexDirection: 'column', gap: '8px' };
const btn = { display: 'flex', alignItems: 'center', gap: '12px', padding: '14px', background: 'none', border: 'none', color: '#a0aec0', cursor: 'pointer', borderRadius: '12px', textAlign: 'left', transition: '0.3s' };
const btnActive = { ...btn, background: '#e67e22', color: 'white' };
const main = { flex: 1, padding: '40px', overflowY: 'auto' };
const loaderStyle = { display:'flex', justifyContent:'center', alignItems:'center', height:'100vh', color:'#e67e22', fontWeight:'bold' };
const searchBox = { display: 'flex', alignItems: 'center', background: 'white', padding: '15px 25px', borderRadius: '15px', marginBottom: '30px', boxShadow: '0 2px 10px rgba(0,0,0,0.05)' };
const input = { flex: 1, border: 'none', outline: 'none', marginLeft: '10px', fontSize: '1rem' };
const tiendaSeccion = { marginBottom: '40px', background: 'white', padding: '20px', borderRadius: '20px', boxShadow: '0 4px 6px rgba(0,0,0,0.02)' };
const headerTienda = { display: 'flex', alignItems: 'center', gap: '15px', marginBottom: '20px' };
const avatarTienda = { width: '48px', height: '48px', background: '#fff3e0', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const metaTienda = { display: 'flex', gap: '10px', fontSize: '0.85rem', color: '#64748b' };
const scrollRow = { display: 'flex', gap: '20px', overflowX: 'auto', paddingBottom: '15px' };
const cardShop = { minWidth: '200px', background: 'white', borderRadius: '15px', border: '1px solid #e2e8f0', overflow: 'hidden', transition: 'transform 0.2s' };
const imgShop = { width: '100%', height: '130px', objectFit: 'cover' };
const btnAdd = { width: '100%', padding: '10px', background: '#1a202c', color: 'white', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', fontWeight:'500' };
const cartContainerStyle = { maxWidth: '500px', margin: '0 auto' };
const centerCont = { maxWidth: '700px', margin: '0 auto' };
const historialCard = { display: 'flex', justifyContent: 'space-between', padding: '20px', background: 'white', borderRadius: '15px', marginBottom: '12px', border: '1px solid #e2e8f0' };
const pPrecio = { fontWeight: 'bold', color: '#2d3748', margin: '8px 0' };
const radarCard = (activo) => ({ background: activo ? '#1a202c' : '#fff', color: activo ? '#fff' : '#1a202c', padding: '20px', borderRadius: '24px', marginBottom: '25px', border: '1px solid #e2e8f0', transition: '0.4s' });
const radarCircle = (activo) => ({ width: '50px', height: '50px', background: activo ? '#e67e22' : '#fff3e0', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' });
const btnRadar = (activo) => ({ padding: '10px 20px', borderRadius: '12px', border: 'none', background: activo ? '#fff' : '#e67e22', color: activo ? '#e67e22' : '#fff', cursor: 'pointer', fontWeight: 'bold' });
const notifBox = { marginTop: '20px', display: 'flex', flexDirection: 'column', gap: '10px' };
const notifItem = { background: '#f8fafc', padding: '12px', borderRadius: '15px', display: 'flex', alignItems: 'center', gap: '12px', color: '#1a202c', borderLeft: '4px solid #e67e22' };
const btnIr = { background: '#1a202c', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '8px', cursor: 'pointer', fontWeight:'bold' };

export default PanelCliente;
